scwin.safeParse = function (val) {
  // 빈칸, null, 콤마(,) 걸러내고 깨끗한 숫자만 뽑아냄
  let num = Number(String(val || "0").replace(/[^0-9.-]/g, ""));
  // 그래도 이상하면(NaN) 무조건 0으로 반환
  return isNaN(num) ? 0 : num;
};
