scwin.f_Retrieve = function () {
  if (ed_srchCloseYear.getValue().trim().length != 4) {
    $c.win.alert($p, "조회년도는 필수입력 입니다.");
    ed_srchCloseYear.focus();
    return;
  }
  if (!$c.gus.cfValidate($p, [tbl_search])) return;
  //    scwin.f_SetGridFormat();  그리드 퍼블적용

  if (scwin.tldily == 0) {
    // checked : 1
    gr_master.setColumnVisible("aftAcctDeptNm", "false");
  } else {
    gr_master.setColumnVisible("aftAcctDeptNm", "true");
  }
  console.log(" scwin.tldily 하위부서포함 : " + scwin.tldily);
  console.log(" scwin.tDist  배부포함  : " + scwin.tDist);
  console.log(" scwin.tDpct  타법인포함: " + scwin.tDpct);
  dma_search.set("closeYear", ed_srchCloseYear.getValue());
  dma_search.set("ver", lc_version.getValue());
  dma_search.set("bookClsCd", lc_srchBookClsCd.getValue());
  dma_search.set("bizDomCd", ""); // As-Is 조회조건 없음
  dma_search.set("lowerDeptIncluYn", scwin.tldily); // 하위부서포함
  dma_search.set("dpctYn", scwin.tDpct); // 하위부서포함
  dma_search.set("distYn", scwin.tDist); // 타법인포함
  //dma_search.set("coCd", scwin.vCoCd);    // 법인코드
  dma_search.set("coCd", "000"); // 법인코드

  var vPreYear = $c.date.addMonth($p, ed_srchCloseYear.getValue() + "01", -11).substring(0, 4); // 전년
  dma_search.set("preCloseYear", vPreYear);
  $c.sbm.execute($p, sbm_master);
};

//-------------------------------------------------------------------------
// 엑셀 Download
//-------------------------------------------------------------------------
scwin.f_Export = async function () {
  // 1. 데이터 없는지 체크
  if (ds_master.getRowCount() == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_WRN_002);
    return;
  }

  // 2. 화면에 보이는 그리드 컬럼 개수 세기 (상단 타이틀 병합용)
  let gridColCount = 0;
  for (let i = 0; i < gr_master.getTotalCol(); i++) {
    if (gr_master.getColumnVisible(i) == true) {
      gridColCount++;
    }
  }
  let yearStr = ed_srchCloseYear.getValue().trim().substring(0, 4);
  let unitStr = lc_unit.getText().split(":").pop().replace(/&amp;nbsp;|&nbsp;/g, "").trim();
  let infoArr = [
  // ① 최상단 여백 (AS-IS의 SetExcelTitle(0, "") 역할)
  {
    rowIndex: 0,
    colIndex: 0,
    colSpan: gridColCount,
    rowSpan: 1,
    text: "",
    drawBorder: false
  },
  // ② 메인 타이틀 (가운데 정렬, 18pt)
  {
    rowIndex: 1,
    colIndex: 0,
    colSpan: gridColCount,
    rowSpan: 1,
    text: "법인별 손익추이(" + yearStr + ")",
    textAlign: "center",
    fontSize: 18,
    drawBorder: false,
    color: "black",
    backgroundColor: "#ffffff"
  },
  // ③ 타이틀 아래 여백 (AS-IS의 첫 번째 skiprow:1 역할)
  {
    rowIndex: 2,
    colIndex: 0,
    colSpan: gridColCount,
    rowSpan: 1,
    text: "",
    drawBorder: false
  },
  // ④ 우측 단위 (오른쪽 정렬, 12pt)
  {
    rowIndex: 3,
    colIndex: 0,
    colSpan: gridColCount,
    rowSpan: 1,
    text: "단위_" + unitStr,
    textAlign: "right",
    fontSize: 12,
    drawBorder: false,
    color: "black",
    backgroundColor: "#ffffff"
  },
  // ⑤ 단위 아래 여백 (AS-IS의 두 번째 skiprow:1 역할)
  {
    rowIndex: 4,
    colIndex: 0,
    colSpan: gridColCount,
    rowSpan: 1,
    text: "",
    drawBorder: false
  }];

  // 5. 다운로드 옵션 세팅
  const options = {
    fileName: "법인별 손익추이_" + yearStr + ".xlsx",
    sheetName: "법인별 손익추이" + yearStr,
    startRowIndex: 5,
    startColumnIndex: 0,
    type: 0,
    colMerge: true,
    colMergeTextAlign: "top",
    useProvider: "false"
  };
  await $c.data.downloadGridViewExcel($p, gr_master, options, infoArr);
};

