scwin.f_changeUnit = function () {
  scwin.cunit = 1;
  if (lc_unit.getValue() == "02") {
    scwin.cunit = 1000;
  }
  if (lc_unit.getValue() == "03") {
    scwin.cunit = 1000000;
  }
  if (lc_unit.getValue() == "04") {
    scwin.cunit = 100000000;
  }
  scwin.f_changeUnitAmt(scwin.cunit);
};

//------------------------------------------------------------------------
// 그리드 컬럼의 금액단위를 정한다.
//------------------------------------------------------------------------
scwin.f_changeUnitAmt = function (unitAmt) {
  var rcnt = ds_master.getRowCount();
  if (rcnt == 0) {
    return;
  }
  ds_master.setBroadcast(false);
  if (lc_srchBookClsCd.getValue() == "931") {
    //요약
    scwin.vAcctCd = "9400001";
    scwin.vAcctCd2 = "5900000";
  } else if (lc_srchBookClsCd.getValue() == "930") {
    //상세
    scwin.vAcctCd = "9300006";
    scwin.vAcctCd2 = "9300002";
  }
  var mAcctCd = "";
  var t_gridUnitAmt = 0;
  const cols_co4040137b = ["befResultTotamt", "aftBizplanTotamt", "aftResultTotamt", "befResultAmt01", "aftBizplanAmt01", "aftResultAmt01", "befResultAmt02", "aftBizplanAmt02", "aftResultAmt02", "befResultAmt03", "aftBizplanAmt03", "aftResultAmt03", "befResultAmt04", "aftBizplanAmt04", "aftResultAmt04", "befResultAmt05", "aftBizplanAmt05", "aftResultAmt05", "befResultAmt06", "aftBizplanAmt06", "aftResultAmt06", "befResultAmt07", "aftBizplanAmt07", "aftResultAmt07", "befResultAmt08", "aftBizplanAmt08", "aftResultAmt08", "befResultAmt09", "aftBizplanAmt09", "aftResultAmt09", "befResultAmt10", "aftBizplanAmt10", "aftResultAmt10", "befResultAmt11", "aftBizplanAmt11", "aftResultAmt11", "befResultAmt12", "aftBizplanAmt12", "aftResultAmt12"];
  for (var i = 0; i < rcnt; i++) {
    mAcctCd = ds_master.getCellData(i, "acctCd");
    if (mAcctCd != scwin.vAcctCd && mAcctCd != scwin.vAcctCd2 && mAcctCd != "9300001" && mAcctCd != "9300003" && mAcctCd != "9300007") {
      for (var j = 0; j < cols_co4040137b.length; j++) {
        if ($c.gus.cfIsNull($p, ds_master.getCellData(i, cols_co4040137b[j])) || !$c.num.isNumber($p, ds_master.getCellData(i, cols_co4040137b[j]))) {
          ds_master.setCellData(i, cols_co4040137b[j], 0);
        } else {
          t_gridUnitAmt = Math.trunc(scwin.safeParse(ds_master.getCellData(i, cols_co4040137b[j])) / unitAmt, 0);
          //  console.log("scwin.t_gridUnitAmt - "+scwin.t_gridUnitAmt);
          if (!$c.gus.cfIsNull($p, t_gridUnitAmt) && $c.num.isNumber($p, t_gridUnitAmt) && !isNaN(t_gridUnitAmt)) {
            ds_master.setCellData(i, cols_co4040137b[j], t_gridUnitAmt);
          } else {
            ds_master.setCellData(i, cols_co4040137b[j], 0);
          }
        }
      }
    }
  }
  ds_master.setBroadcast(true, true);
};
